+    fn first_divergence(a: &[u64], b: &[u64]) -> Option<usize> {
+        let n = a.len().min(b.len());
+        for i in 0..n {
+            if a[i] != b[i] {
+                return Some(i);
+            }
+        }
+        if a.len() != b.len() {
+            return Some(n);
+        }
+        None
+    }
